mapper.sql:
WHERE 1 = 1

    AND s.course_id = #{request.courseId}


    AND s.knowledge_base_id = #{request.knowledgeBaseId}


    AND l.query_mode = #{request.mode}


    AND l.task_status = #{request.taskStatus}


    AND l.created_at >= #{request.createdFrom}


    AND l.created_at <= #{request.createdTo}


    AND EXISTS (
      SELECT 1 FROM qa_message_feedback f
      WHERE f.retrieval_log_id = l.id AND f.rating = #{request.feedbackRating}
    )


    AND EXISTS (
      SELECT 1 FROM qa_message_feedback f
      WHERE f.retrieval_log_id = l.id AND CAST(f.tags AS CHAR) LIKE CONCAT('%', #{request.feedbackTag}, '%')
    )


    AND l.routing_confidence_band = #{request.routingConfidenceBand}


    AND l.routing_review_priority = #{request.reviewPriority}


    AND (
      c.course_name LIKE CONCAT('%', #{request.keyword}, '%')
      OR kb.name LIKE CONCAT('%', #{request.keyword}, '%')
      OR u.username LIKE CONCAT('%', #{request.keyword}, '%')
      OR u.display_name LIKE CONCAT('%', #{request.keyword}, '%')
      OR CAST(l.id AS CHAR) LIKE CONCAT('%', #{request.keyword}, '%')
    )


    AND (
      c.access_policy = 'public'
      OR EXISTS (
        SELECT 1 FROM course_memberships cm
        WHERE cm.course_id = s.course_id
          AND cm.user_id = #{currentUserId}
          AND cm.status = 'active'
          AND (cm.effective_from IS NULL OR cm.effective_from <= NOW())
          AND (cm.effective_to IS NULL OR cm.effective_to > NOW())
          AND (cm.expires_at IS NULL OR cm.expires_at > NOW())
      )
    )

mapper.select:
SELECT



ORDER BY l.created_at DESC, l.id DESC
LIMIT #{size} OFFSET #{offset}

SELECT f.id AS id, f.message_id AS messageId, f.retrieval_log_id AS retrievalLogId, f.session_id AS sessionId, f.user_id AS userId, u.username AS username, u.display_name AS displayName, f.rating AS rating, CAST(f.tags AS CHAR) AS tags, f.comment AS comment, f.created_at AS createdAt, f.updated_at AS updatedAt FROM qa_message_feedback f LEFT JOIN users u ON u.id = f.user_id WHERE f.retrieval_log_id IN
#{id}
ORDER BY f.created_at DESC, f.id DESC
